output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?team(COUNT(?championship) AS ?count) WHERE {
  VALUES ?team {
    wd:Q6837794 wd:Q2927468
  }
  ?team wdt:P2522 | wdt:P166 ?championship .
  ?championship rdfs:label ?label .
  FILTER(LANG(?label) = 'en')
  FILTER(REGEX(?label , 'national championship|AP champion' , 'i'))
}
GROUP BY ?team
